from flask import Flask, request, abort
from prometheus_client import Counter, generate_latest, CONTENT_TYPE_LATEST
import re

app = Flask(__name__)

# Define a regex pattern for validating user_id and session_id
USER_ID_PATTERN = re.compile(r'^[a-zA-Z0-9_-]{1,64}$')
SESSION_ID_PATTERN = re.compile(r'^[a-zA-Z0-9_-]{1,64}$')
PATH_PATTERN = re.compile(r'^/[\w/-]*$')

# Prometheus Counter for tracking requests
REQUEST_COUNTER = Counter(
    'http_requests_total',
    'Total HTTP Requests',
    ['user_id', 'session_id', 'path']
)

def validate_input(user_id, session_id, path):
    if not USER_ID_PATTERN.match(user_id):
        abort(400, 'Invalid user_id')
    if not SESSION_ID_PATTERN.match(session_id):
        abort(400, 'Invalid session_id')
    if not PATH_PATTERN.match(path):
        abort(400, 'Invalid path')

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': CONTENT_TYPE_LATEST}

@app.route('/track', methods=['POST'])
def track():
    user_id = request.form.get('user_id')
    session_id = request.form.get('session_id')
    path = request.form.get('path')

    validate_input(user_id, session_id, path)

    REQUEST_COUNTER.labels(user_id=user_id, session_id=session_id, path=path).inc()
    return 'Request tracked', 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=8000)